"use client";

import { useState } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getRandomComplete } from "@/lib/learningMessages";
import { getNextStep } from "@/content";

// ===== 类型 =====
interface EdgeInfo {
  label: string;
  value: number;
}

interface ExerciseState {
  step: number; // 0..4
  total: number;
  done: boolean;
}

// ===== 常量 =====
const RECT_WIDTH = 300;
const RECT_HEIGHT = 180;
const SQUARE_SIZE = 150;
const STROKE = 20;

const RECT_EDGES: EdgeInfo[] = [
  { label: "上边", value: 10 },
  { label: "右边", value: 6 },
  { label: "下边", value: 10 },
  { label: "左边", value: 6 },
];

const SQUARE_EDGES: EdgeInfo[] = [
  { label: "上边", value: 8 },
  { label: "右边", value: 8 },
  { label: "下边", value: 8 },
  { label: "左边", value: 8 },
];

export default function CountPage() {
  const [rect, setRect] = useState<ExerciseState>({
    step: 0,
    total: 0,
    done: false,
  });
  const [square, setSquare] = useState<ExerciseState>({
    step: 0,
    total: 0,
    done: false,
  });
  const [showDiscovery, setShowDiscovery] = useState(false);
  const [completeMsg, setCompleteMsg] = useState("");

  const allDone = rect.done && square.done;
  const nextStep = getNextStep("perimeter", "count");

  const handleAddRectEdge = () => {
    if (rect.done) return;
    const nextStep = rect.step + 1;
    const edge = RECT_EDGES[rect.step];
    const newTotal = rect.total + edge.value;
    const done = nextStep >= RECT_EDGES.length;
    setRect({ step: nextStep, total: newTotal, done });
    if (done) {
      setTimeout(() => setShowDiscovery(true), 600);
    }
  };

  const handleAddSquareEdge = () => {
    if (square.done) return;
    const nextStep = square.step + 1;
    const edge = SQUARE_EDGES[square.step];
    const newTotal = square.total + edge.value;
    const done = nextStep >= SQUARE_EDGES.length;
    setSquare({ step: nextStep, total: newTotal, done });
    if (done && rect.done) {
      setCompleteMsg(getRandomComplete());
    }
  };

  const resetAll = () => {
    setRect({ step: 0, total: 0, done: false });
    setSquare({ step: 0, total: 0, done: false });
    setShowDiscovery(false);
    setCompleteMsg("");
  };

  // 渲染长方形边高亮
  const renderRectEdges = () => {
    const edges = [
      // 上边
      { x: 0, y: 0, w: RECT_WIDTH, h: STROKE },
      // 右边
      { x: RECT_WIDTH - STROKE, y: 0, w: STROKE, h: RECT_HEIGHT },
      // 下边
      { x: 0, y: RECT_HEIGHT - STROKE, w: RECT_WIDTH, h: STROKE },
      // 左边
      { x: 0, y: 0, w: STROKE, h: RECT_HEIGHT },
    ];
    return edges.map((e, i) => {
      const active = i < rect.step;
      return (
        <rect
          key={i}
          x={e.x}
          y={e.y}
          width={e.w}
          height={e.h}
          rx={i === 0 || i === 2 ? 6 : 0}
          fill={active ? "var(--primary)" : "transparent"}
          fillOpacity={active ? 0.35 : 0}
          stroke={active ? "var(--primary)" : "var(--border)"}
          strokeWidth={active ? 3 : 1.5}
          className="transition-all duration-500"
        />
      );
    });
  };

  // 渲染正方形边高亮
  const renderSquareEdges = () => {
    const edges = [
      { x: 0, y: 0, w: SQUARE_SIZE, h: STROKE },
      { x: SQUARE_SIZE - STROKE, y: 0, w: STROKE, h: SQUARE_SIZE },
      { x: 0, y: SQUARE_SIZE - STROKE, w: SQUARE_SIZE, h: STROKE },
      { x: 0, y: 0, w: STROKE, h: SQUARE_SIZE },
    ];
    return edges.map((e, i) => {
      const active = i < square.step;
      return (
        <rect
          key={i}
          x={e.x}
          y={e.y}
          width={e.w}
          height={e.h}
          rx={i === 0 || i === 2 ? 6 : 0}
          fill={active ? "var(--accent)" : "transparent"}
          fillOpacity={active ? 0.35 : 0}
          stroke={active ? "var(--accent)" : "var(--border)"}
          strokeWidth={active ? 3 : 1.5}
          className="transition-all duration-500"
        />
      );
    });
  };

  return (
    <StepShell topicId="perimeter" stepId="count">
      <div className="space-y-6">
        {/* 练习 1: 长方形周长 */}
        <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
          <h2 className="text-center text-lg font-bold text-[var(--text)]">
            练习 1：数出长方形的周长
          </h2>
          <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
            长 = 10cm，宽 = 6cm。点击"加一边"，把四条边加起来
          </p>

          <div className="mt-6 flex justify-center">
            <svg
              width={RECT_WIDTH}
              height={RECT_HEIGHT}
              viewBox={`0 0 ${RECT_WIDTH} ${RECT_HEIGHT}`}
              className="rounded-2xl"
              style={{ background: "var(--bg-soft)" }}
            >
              {/* 长方形底色 */}
              <rect
                x={STROKE / 2}
                y={STROKE / 2}
                width={RECT_WIDTH - STROKE}
                height={RECT_HEIGHT - STROKE}
                rx={12}
                fill="var(--primary)"
                fillOpacity={0.06}
                stroke="var(--primary)"
                strokeWidth={2}
                strokeDasharray="6 4"
              />
              {/* 边高亮 */}
              {renderRectEdges()}
              {/* 边数值标注 */}
              <text
                x={RECT_WIDTH / 2}
                y={STROKE / 2 + 5}
                textAnchor="middle"
                fill="var(--text)"
                fontSize={12}
                fontWeight="bold"
              >
                10cm
              </text>
              <text
                x={RECT_WIDTH - STROKE / 2}
                y={RECT_HEIGHT / 2 + 4}
                textAnchor="middle"
                fill="var(--text)"
                fontSize={12}
                fontWeight="bold"
              >
                6cm
              </text>
              <text
                x={RECT_WIDTH / 2}
                y={RECT_HEIGHT - STROKE / 2 + 5}
                textAnchor="middle"
                fill="var(--text)"
                fontSize={12}
                fontWeight="bold"
              >
                10cm
              </text>
              <text
                x={STROKE / 2}
                y={RECT_HEIGHT / 2 + 4}
                textAnchor="middle"
                fill="var(--text)"
                fontSize={12}
                fontWeight="bold"
              >
                6cm
              </text>
            </svg>
          </div>

          {/* 累加显示 */}
          <div className="mt-4 text-center">
            {rect.step > 0 && (
              <p className="animate-float-in text-lg font-bold text-[var(--primary)]">
                {RECT_EDGES.slice(0, rect.step)
                  .map((e) => e.value)
                  .join(" + ")} = {rect.total}cm
              </p>
            )}
          </div>

          {/* 操作按钮 */}
          <div className="mt-4 flex justify-center">
            {!rect.done ? (
              <button
                onClick={handleAddRectEdge}
                className="rounded-full bg-[var(--primary)] px-6 py-3 text-sm font-semibold text-white shadow-[var(--shadow-sm)] transition-all hover:scale-105"
              >
                {rect.step === 0
                  ? "加一边 →"
                  : `再加一边 (${RECT_EDGES[rect.step].label})`}
              </button>
            ) : (
              <div className="animate-float-in rounded-xl bg-[var(--primary)]/10 px-6 py-3 text-center">
                <p className="font-bold text-[var(--text)]">
                  周长 = 10 + 6 + 10 + 6 = 32cm
                </p>
              </div>
            )}
          </div>
        </div>

        {/* 练习 2: 正方形周长 */}
        <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
          <h2 className="text-center text-lg font-bold text-[var(--text)]">
            练习 2：数出正方形的周长
          </h2>
          <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
            边长 = 8cm。点击"加一边"，把四条边加起来
          </p>

          <div className="mt-6 flex justify-center">
            <svg
              width={SQUARE_SIZE}
              height={SQUARE_SIZE}
              viewBox={`0 0 ${SQUARE_SIZE} ${SQUARE_SIZE}`}
              className="rounded-2xl"
              style={{ background: "var(--bg-soft)" }}
            >
              {/* 正方形底色 */}
              <rect
                x={STROKE / 2}
                y={STROKE / 2}
                width={SQUARE_SIZE - STROKE}
                height={SQUARE_SIZE - STROKE}
                rx={12}
                fill="var(--accent)"
                fillOpacity={0.06}
                stroke="var(--accent)"
                strokeWidth={2}
                strokeDasharray="6 4"
              />
              {/* 边高亮 */}
              {renderSquareEdges()}
              {/* 边数值标注 */}
              <text
                x={SQUARE_SIZE / 2}
                y={STROKE / 2 + 5}
                textAnchor="middle"
                fill="var(--text)"
                fontSize={12}
                fontWeight="bold"
              >
                8cm
              </text>
              <text
                x={SQUARE_SIZE - STROKE / 2}
                y={SQUARE_SIZE / 2 + 4}
                textAnchor="middle"
                fill="var(--text)"
                fontSize={12}
                fontWeight="bold"
              >
                8cm
              </text>
              <text
                x={SQUARE_SIZE / 2}
                y={SQUARE_SIZE - STROKE / 2 + 5}
                textAnchor="middle"
                fill="var(--text)"
                fontSize={12}
                fontWeight="bold"
              >
                8cm
              </text>
              <text
                x={STROKE / 2}
                y={SQUARE_SIZE / 2 + 4}
                textAnchor="middle"
                fill="var(--text)"
                fontSize={12}
                fontWeight="bold"
              >
                8cm
              </text>
            </svg>
          </div>

          {/* 累加显示 */}
          <div className="mt-4 text-center">
            {square.step > 0 && (
              <p className="animate-float-in text-lg font-bold text-[var(--accent)]">
                {SQUARE_EDGES.slice(0, square.step)
                  .map((e) => e.value)
                  .join(" + ")} = {square.total}cm
              </p>
            )}
          </div>

          {/* 操作按钮 */}
          <div className="mt-4 flex justify-center">
            {!square.done ? (
              <button
                onClick={handleAddSquareEdge}
                disabled={!rect.done}
                className="rounded-full bg-[var(--accent)] px-6 py-3 text-sm font-semibold text-white shadow-[var(--shadow-sm)] transition-all hover:scale-105 disabled:opacity-30 disabled:cursor-not-allowed"
              >
                {square.step === 0
                  ? "加一边 →"
                  : `再加一边 (${SQUARE_EDGES[square.step].label})`}
              </button>
            ) : (
              <div className="animate-float-in rounded-xl bg-[var(--accent)]/10 px-6 py-3 text-center">
                <p className="font-bold text-[var(--text)]">
                  周长 = 8 + 8 + 8 + 8 = 32cm
                </p>
              </div>
            )}
          </div>
        </div>

        {/* 发现提示 */}
        {showDiscovery && (
          <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--accent2)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <h3 className="mb-4 text-center text-lg font-bold text-[var(--text)]">
              你发现了吗？
            </h3>
            <div className="grid gap-4 sm:grid-cols-2">
              <div className="rounded-xl bg-[var(--primary)]/5 p-4">
                <p className="font-semibold text-[var(--primary)]">长方形</p>
                <p className="mt-1 text-sm text-[var(--text)]">
                  长 + 宽 + 长 + 宽
                </p>
                <p className="mt-1 text-sm font-bold text-[var(--text)]">
                  = 2 × 长 + 2 × 宽
                </p>
              </div>
              <div className="rounded-xl bg-[var(--accent)]/5 p-4">
                <p className="font-semibold text-[var(--accent)]">正方形</p>
                <p className="mt-1 text-sm text-[var(--text)]">
                  边 + 边 + 边 + 边
                </p>
                <p className="mt-1 text-sm font-bold text-[var(--text)]">
                  = 4 × 边
                </p>
              </div>
            </div>
          </div>
        )}

        {/* 完成卡片 */}
        {allDone && (
          <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--accent2)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]">
            <div className="text-4xl">🎉</div>
            <h3 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg || "太棒了！你学会了算周长！"}
            </h3>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              长方形的周长 = 长 + 宽 + 长 + 宽
              <br />
              正方形的周长 = 边长 + 边长 + 边长 + 边长
            </p>
            <div className="mt-5 flex justify-center gap-3">
              <button
                onClick={resetAll}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-soft)] px-5 py-2.5 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-card)]"
              >
                再玩一次
              </button>
              {nextStep && (
                <Link
                  href={nextStep.path}
                  className="rounded-full bg-[var(--accent)] px-6 py-2.5 text-sm font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                >
                  下一步：{nextStep.label} →
                </Link>
              )}
            </div>
          </div>
        )}
      </div>
    </StepShell>
  );
}
